import { useSelector } from 'react-redux';
import { useLocation, NavLink } from "react-router-dom";
import "./notification.css";
import {format} from 'timeago.js';
import { useEffect } from 'react';
import { updatedNotification } from '../../redux/apiCalls';
import { useDispatch } from "react-redux";

const Notification = () => {
    const location = useLocation();
    const notificationId = location.pathname.split("/")[2];
    const notification = useSelector(state => 
        state.notification.notifications.find(notification => notification._id === notificationId)
    );
    const dispatch = useDispatch();

    useEffect(() => {
        const notificationToUpdate = {
            ...notification,
            read: !notification.read
        }
        updatedNotification(notificationId, notificationToUpdate, dispatch);
    }, [dispatch])

    if (!notification) {
        return (
            <section>
                <h2>Notification not found!</h2>
            </section>
        )
    }

  return (
    <section className='notificationContainer'>
      <article className="notification">
        <h2>{notification.subject}</h2>
            <div className="topLine">
                <div>
                    <b>Received from username</b>: {notification.username}
                </div>
                <div>
                    <b>userId</b>: {notification.userId}
                </div>
            </div>
            <div className="middleLine">
                <b>Full Name</b>: 
                <span> {notification.title ? notification.title : ''} </span> 
                <span>{notification.firstName ? notification.firstName : ''} </span>
                <span>{notification.lastName ? notification.lastName : ''}</span>
            </div>
            <div className="middleLine">
                <div className="emailLine"><b>Email</b>: {notification.email ? notification.email : 'unknown'}</div>
            </div>
            <div className="middleLine">
                <b>Telephone</b>: {notification.telephone ? notification.telephone : 'unknown'}
            </div>
        <p className='notificationContent'>{notification.message}</p>
        <div className='bottomLine'>
            <p className="timeSent">{format(notification.createdAt)}</p>
            {notification.userId !== 'unregistered' && 
            <NavLink to={`/user/${notification.userId}`}>
                <p className="timeSent">All notifications from this user</p>
            </NavLink>}
        </div>
      </article>
    </section>
  )
}

export default Notification;
